import hashlib
import secrets


class TokenStore:
    def __init__(self):
        self._by_token = {}

    def issue(self, user_id: int) -> str:
        tok = secrets.token_hex(8)
        self._by_token[tok] = user_id
        return tok

    def lookup(self, token: str):
        return self._by_token.get(token)

    def rotate(self, user_id: int) -> str:
        new = secrets.token_hex(8)
        self._by_token[new] = user_id
        return new

    def revoke(self, token: str) -> bool:
        return self._by_token.pop(token, None) is not None

